insert into cms_tour_options_content (id, content, updated_at)
values (1, '{"options":[{"key":"customOption1","price":50000,"title":{"ko":"고급 게르 추가","ja":"プレミアムゲル","en":"Premium ger upgrade"},"desc":{"ko":"숙소를 한 단계 업그레이드해서 더 편안하게 머물 수 있어요.","ja":"宿泊をワンランク上の快適さにアップグレードします。","en":"A more comfortable accommodation setup for the trip."},"details":{"ko":["기본 게르보다 넓고 아늑한 실내","침구와 휴식 환경 업그레이드","프리미엄 일정과 잘 어울리는 숙소 구성"],"ja":["より広く落ち着いた室内空間","寝具や室内快適性をアップグレード","プレミアム旅程に合う宿泊構成"],"en":["More spacious and refined ger interior","Upgraded bedding and in-room comfort","A better fit for premium-style itineraries"]},"photos":["/images/null.png","/images/null.png","/images/null.png"]},{"key":"customOption2","price":50000,"title":{"ko":"공항 픽업 포함","ja":"空港ピックアップ","en":"Airport pickup"},"desc":{"ko":"도착과 출발 이동을 더 편하게 만들어드려요.","ja":"到着と出発の移動をもっとスムーズにします。","en":"A smoother arrival and departure experience."},"details":{"ko":["비행 시간에 맞춘 공항 미팅","숙소 또는 미팅 포인트까지 바로 이동","야간이나 이른 도착 일정에도 편리한 옵션"],"ja":["フライト時間に合わせた空港ミーティング","宿泊先または集合場所まで直接移動","深夜や早朝の到着にも便利"],"en":["Airport meet-up based on your flight time","Direct transfer to your stay or meeting point","Especially useful for late-night or early arrivals"]},"photos":["/images/null.png","/images/null.png","/images/null.png"]},{"key":"customOption3","price":50000,"title":{"ko":"프라이빗 가이드","ja":"プライベートガイド","en":"Private guide"},"desc":{"ko":"우리 일행 속도에 맞춘 더 세심한 진행을 도와드려요.","ja":"グループに合わせた、よりきめ細かな進行をサポートします。","en":"A more tailored pace and experience for your group."},"details":{"ko":["소규모 인원에 맞춘 일정 조율","현장 설명과 여행 동선 안내 강화","사진, 휴식, 이동 페이스를 유연하게 조정"],"ja":["少人数向けの柔軟な行程調整","現地での案内や説明をより丁寧に対応","写真や休憩、移動ペースも柔軟に調整可能"],"en":["Flexible pacing for smaller groups","More personal support before and during the trip","Easier adjustments for photos, breaks, and timing"]},"photos":["/images/null.png","/images/null.png","/images/null.png"]},{"key":"customOption4","price":50000,"title":{"ko":"캠프파이어","ja":"キャンプファイヤー","en":"Campfire experience"},"desc":{"ko":"저녁 시간에 모닥불과 함께 분위기 있는 시간을 즐길 수 있어요.","ja":"夜にたき火を囲みながら、特別な雰囲気を楽しめるオプションです。","en":"Add a cozy evening campfire to make the trip feel more memorable."},"details":{"ko":["전용 캠프파이어 세팅 진행","간단한 스낵 또는 티타임과 함께 이용","별 보기와 야간 감성을 더해주는 인기 옵션"],"ja":["専用のキャンプファイヤーセットを用意","軽いスナックやティータイムと相性が良い構成","星空鑑賞や夜の思い出づくりにぴったり"],"en":["A dedicated campfire setup in the evening","Pairs well with light snacks or tea time","Great for stargazing and relaxed night moments"]},"photos":["/images/null.png","/images/null.png","/images/null.png"]},{"key":"customOption5","price":50000,"title":{"ko":"고급 차량","ja":"高級車両","en":"Premium vehicle"},"desc":{"ko":"이동 구간을 더 쾌적하고 여유롭게 만들어주는 업그레이드예요.","ja":"移動時間をより快適でゆったりしたものにするアップグレードです。","en":"Upgrade your transfers for a smoother and more comfortable ride."},"details":{"ko":["더 넓고 편안한 좌석 구성","장거리 이동 시 피로도를 줄여주는 차량","가족 또는 프리미엄 여행에 잘 어울리는 선택"],"ja":["より広く快適な座席構成","長距離移動でも疲れにくい車両","家族旅行やプレミアム旅程に似合う選択"],"en":["More spacious and comfortable seating","Better fit for longer driving segments","A strong choice for families or premium-style trips"]},"photos":["/images/null.png","/images/null.png","/images/null.png"]}]}'::jsonb, '2026-05-01T01:34:57.815Z')
