insert into cms_tour_customize_content (id, content, updated_at)
values (1, '{"regions":{"south":{"basePrice":1390000,"destinations":[{"id":"south-destination-1","image":"/images/null.png","title":{"ko":"고비 사막","ja":"ゴビ砂漠","en":"Gobi Desert"},"desc":{"ko":"끝없이 펼쳐지는 사막과 별빛이 인상적인 대표 코스예요.","ja":"広大な砂漠と星空が印象的な南部の定番ルートです。","en":"A signature southern route with wide desert views and striking night skies."}},{"id":"south-destination-2","image":"/images/null.png","title":{"ko":"욜링암 협곡","ja":"ヨリーンアム渓谷","en":"Yolyn Am Canyon"},"desc":{"ko":"깊은 협곡과 시원한 바람을 느낄 수 있는 명소예요.","ja":"深い渓谷と涼しい空気を楽しめる名所です。","en":"A dramatic canyon known for its cool air and layered cliffs."}},{"id":"south-destination-3","image":"/images/null.png","title":{"ko":"바양작","ja":"バヤンザグ","en":"Bayanzag"},"desc":{"ko":"붉은 절벽과 공룡 화석 이야기로 유명한 지역이에요.","ja":"赤い断崖と恐竜化石で知られる人気スポットです。","en":"A famous red-cliff area known for dinosaur fossil discoveries."}},{"id":"south-destination-4","image":"/images/null.png","title":{"ko":"홍고린 엘스","ja":"ホンゴル砂丘","en":"Khongor Sand Dunes"},"desc":{"ko":"웅장한 모래언덕과 낙타 체험으로 인기 있는 장소예요.","ja":"壮大な砂丘とラクダ体験で人気のエリアです。","en":"Massive dunes and camel rides make this one of the most iconic stops."}}],"activities":[{"id":"south-activity-1","image":"/images/null.png","price":50000,"title":{"ko":"낙타 체험","ja":"ラクダ体験","en":"Camel riding"},"desc":{"ko":"고비 사막의 모래언덕에서 낙타를 타고 사막 풍경을 천천히 즐깁니다.","ja":"ゴビ砂漠の砂丘でラクダに乗り、砂漠の景色をゆっくり楽しみます。","en":"Ride a camel across the Gobi dunes and take in the desert scenery at a slower pace."}},{"id":"south-activity-2","image":"/images/null.png","price":30000,"title":{"ko":"사막 별보기","ja":"砂漠の星空鑑賞","en":"Desert stargazing"},"desc":{"ko":"빛 공해가 적은 사막 밤하늘에서 별과 은하수를 감상합니다.","ja":"光の少ない砂漠の夜空で星や天の川を眺めます。","en":"Watch the stars and Milky Way under the dark southern desert sky."}},{"id":"south-activity-3","image":"/images/null.png","price":40000,"title":{"ko":"협곡 트레킹","ja":"渓谷トレッキング","en":"Canyon trekking"},"desc":{"ko":"욜링암 협곡의 바위길을 따라 걸으며 고비의 지형을 가까이서 봅니다.","ja":"ヨリーンアム渓谷の岩道を歩き、ゴビの地形を間近で感じます。","en":"Walk through Yolyn Am Canyon and explore the dramatic rock formations up close."}}]},"north":{"basePrice":1790000,"destinations":[{"id":"north-destination-1","image":"/images/null.png","title":{"ko":"홉스골 호수","ja":"フブスグル湖","en":"Khuvsgul Lake"},"desc":{"ko":"맑고 깊은 호수 풍경을 즐길 수 있는 북부 대표 여행지예요.","ja":"澄んだ湖の風景を楽しめる北部の代表的な旅先です。","en":"A northern classic with clear lake views and fresh forest air."}},{"id":"north-destination-2","image":"/images/null.png","title":{"ko":"하트갈","ja":"ハトガル","en":"Khatgal"},"desc":{"ko":"호숫가 마을의 여유로운 분위기를 느낄 수 있어요.","ja":"湖畔の落ち着いた雰囲気が魅力の町です。","en":"A peaceful lakeside town with a relaxed northern atmosphere."}},{"id":"north-destination-3","image":"/images/null.png","title":{"ko":"차탕 마을","ja":"ツァータン村","en":"Tsaatan Village"},"desc":{"ko":"순록 문화와 북부 소수민족의 삶을 가까이서 만날 수 있어요.","ja":"トナカイ文化にふれられる特別な地域です。","en":"A rare chance to experience reindeer culture in the north."}},{"id":"north-destination-4","image":"/images/null.png","title":{"ko":"우란 타이가","ja":"ウランタイガ","en":"Ulaan Taiga"},"desc":{"ko":"숲과 초원이 어우러진 북부의 깊은 자연을 만나는 코스예요.","ja":"森と草原が広がる北部の大自然を感じられます。","en":"A deep-nature area of forests and open taiga landscapes."}}],"activities":[{"id":"north-activity-1","image":"/images/null.png","price":60000,"title":{"ko":"호수 보트 투어","ja":"湖ボートツアー","en":"Lake boat tour"},"desc":{"ko":"홉스골 호수 위에서 맑은 물빛과 산 풍경을 함께 감상합니다.","ja":"フブスグル湖で澄んだ湖水と山の景色を楽しみます。","en":"Cruise on Khuvsgul Lake with clear water and mountain views around you."}},{"id":"north-activity-2","image":"/images/null.png","price":50000,"title":{"ko":"승마 트레킹","ja":"乗馬トレッキング","en":"Horse trekking"},"desc":{"ko":"호숫가와 숲길을 따라 말과 함께 북부 자연을 경험합니다.","ja":"湖畔や森の道を馬で進み、北部の自然を体験します。","en":"Ride along lakeside and forest trails in Mongolia''s northern landscape."}},{"id":"north-activity-3","image":"/images/null.png","price":70000,"title":{"ko":"순록 마을 방문","ja":"トナカイ村訪問","en":"Reindeer village visit"},"desc":{"ko":"북부 소수민족의 순록 문화와 생활 방식을 가까이서 만납니다.","ja":"北部少数民族のトナカイ文化と暮らしにふれます。","en":"Visit a reindeer community and learn about northern nomadic life."}}]},"central":{"basePrice":390000,"destinations":[{"id":"central-destination-1","image":"/images/null.png","title":{"ko":"테를지 국립공원","ja":"テレルジ国立公園","en":"Terelj National Park"},"desc":{"ko":"초원과 바위산 풍경이 조화로운 가장 인기 많은 중부 코스예요.","ja":"草原と奇岩の景観が美しい中部の人気コースです。","en":"A favorite central route with steppe scenery and unique rock formations."}},{"id":"central-destination-2","image":"/images/null.png","title":{"ko":"칭기즈칸 동상","ja":"チンギスハーン騎馬像","en":"Chinggis Khaan Statue"},"desc":{"ko":"광활한 초원 위 거대한 기마상으로 유명한 랜드마크예요.","ja":"大草原に立つ巨大な騎馬像で有名なランドマークです。","en":"A major landmark featuring the giant horse statue on the steppe."}},{"id":"central-destination-3","image":"/images/null.png","title":{"ko":"엘승타사르해","ja":"エルセンタサルハイ","en":"Elsen Tasarkhai"},"desc":{"ko":"사막과 초원이 함께 펼쳐지는 독특한 풍경의 지역이에요.","ja":"砂丘と草原が同時に楽しめる独特な景観です。","en":"A unique area where sand dunes and grasslands meet."}},{"id":"central-destination-4","image":"/images/null.png","title":{"ko":"허스테이 국립공원","ja":"ホスタイ国立公園","en":"Hustai National Park"},"desc":{"ko":"야생말 타키와 넓은 초원을 만날 수 있는 자연 보호구역이에요.","ja":"野生馬タヒと広大な草原に出会える保護区です。","en":"A protected grassland area known for wild horses and open landscapes."}}],"activities":[{"id":"central-activity-1","image":"/images/null.png","price":40000,"title":{"ko":"초원 승마","ja":"草原乗馬","en":"Steppe horseback riding"},"desc":{"ko":"테를지 초원에서 짧고 부담 없는 승마 체험을 즐깁니다.","ja":"テレルジの草原で気軽な乗馬体験を楽しみます。","en":"Enjoy an accessible horseback ride across the Terelj steppe."}},{"id":"central-activity-2","image":"/images/null.png","price":30000,"title":{"ko":"유목민 게르 방문","ja":"遊牧民ゲル訪問","en":"Nomad ger visit"},"desc":{"ko":"현지 유목민 게르를 방문해 차와 간단한 문화를 체험합니다.","ja":"現地の遊牧民ゲルを訪れ、お茶や文化体験を楽しみます。","en":"Visit a local ger for tea and a short introduction to nomadic culture."}},{"id":"central-activity-3","image":"/images/null.png","price":35000,"title":{"ko":"칭기즈칸 전망대","ja":"チンギスハーン展望台","en":"Chinggis Khan viewpoint"},"desc":{"ko":"칭기즈칸 동상 전망대에서 초원의 스케일을 한눈에 봅니다.","ja":"チンギスハーン像の展望台から草原を一望します。","en":"Take in wide steppe views from the Chinggis Khan statue viewpoint."}}]},"west":{"basePrice":2490000,"destinations":[{"id":"west-destination-1","image":"/images/null.png","title":{"ko":"알타이 산맥","ja":"アルタイ山脈","en":"Altai Mountains"},"desc":{"ko":"험준한 산세와 대자연의 스케일이 압도적인 서부 대표 코스예요.","ja":"雄大な山並みが広がる西部の代表的なルートです。","en":"A grand western route with rugged mountains and huge natural scale."}},{"id":"west-destination-2","image":"/images/null.png","title":{"ko":"올기","ja":"ウルギー","en":"Olgii"},"desc":{"ko":"카자흐 문화와 독특한 서부 분위기를 느낄 수 있는 도시예요.","ja":"カザフ文化が色濃く残る西部の中心都市です。","en":"A western city known for strong Kazakh culture and mountain access."}},{"id":"west-destination-3","image":"/images/null.png","title":{"ko":"차강노르","ja":"ツァガーンノール","en":"Tsagaan Nuur"},"desc":{"ko":"광활한 평원과 호수 풍경이 조용하게 펼쳐지는 지역이에요.","ja":"静かな湖と平原の景色が魅力の地域です。","en":"A calm region of lakes and wide plains in western Mongolia."}},{"id":"west-destination-4","image":"/images/null.png","title":{"ko":"톨보 호수","ja":"トルボ湖","en":"Tolbo Lake"},"desc":{"ko":"산과 호수가 함께 어우러진 서부의 장대한 절경이에요.","ja":"山と湖が織りなす壮大な景観を楽しめます。","en":"A dramatic lake-and-mountain landscape that defines the west."}}],"activities":[{"id":"west-activity-1","image":"/images/null.png","price":80000,"title":{"ko":"독수리 문화 체험","ja":"鷹匠文化体験","en":"Eagle culture experience"},"desc":{"ko":"서부 카자흐 유목민의 독수리 사냥 문화를 가까이서 배웁니다.","ja":"西部カザフ遊牧民の鷹匠文化を間近で学びます。","en":"Learn about Kazakh eagle hunting traditions in western Mongolia."}},{"id":"west-activity-2","image":"/images/null.png","price":60000,"title":{"ko":"알타이 트레킹","ja":"アルタイトレッキング","en":"Altai trekking"},"desc":{"ko":"알타이 산맥의 능선과 계곡을 따라 서부의 대자연을 걷습니다.","ja":"アルタイ山脈の稜線や谷を歩き、西部の大自然を感じます。","en":"Trek through ridges and valleys in the Altai Mountains."}},{"id":"west-activity-3","image":"/images/null.png","price":50000,"title":{"ko":"카자흐 전통 마을","ja":"カザフ伝統村","en":"Kazakh village visit"},"desc":{"ko":"올기 주변 마을에서 카자흐 음식과 생활 문화를 경험합니다.","ja":"ウルギー周辺の村でカザフの食と暮らしにふれます。","en":"Experience Kazakh food and daily culture in a village near Ulgii."}}]}}}'::jsonb, '2026-05-01T01:34:57.817Z')
